// And groups predicates with the AND operator between them.
func And(predicates ...predicate.LoanContract) predicate.LoanContract {
	return predicate.LoanContract(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.LoanContract) predicate.LoanContract {
	return predicate.LoanContract(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.LoanContract) predicate.LoanContract {
	return predicate.LoanContract(sql.NotPredicates(p))
}
